import { tags } from 'decantr/tags';
import { css } from 'decantr/css';
import { Card, Input, Select, Switch, Button, Label, Textarea } from 'decantr/components';

code.example:
function FormSections({ onSave, onCancel }) {
  const { div, h3, p, form } = tags;

  return form({ class: css('_flex _col _gap6 _p4'), onsubmit: e => { e.preventDefault(); onSave?.(); } },
    Card({ class: css('_flex _col _gap4 _p6') },
      div({ class: css('_grid _gc1 _lg:gc2 _gap4') },
        div({ class: css('_flex _col _gap1') },
          h3({ class: css('_heading4') }, 'Profile'),
          p({ class: css('_bodysm _fgmuted') }, 'Your personal information')
        ),
        div({ class: css('_flex _col _gap4') },
          div({ class: css('_flex _col _gap2') },
            Label({}, 'Display Name'),
            Input({ placeholder: 'Enter your name' })
          ),
          div({ class: css('_flex _col _gap2') },
            Label({}, 'Bio'),
            Textarea({ placeholder: 'Tell us about yourself', rows: 3 })
          )
        )
      )
    ),
    Card({ class: css('_flex _col _gap4 _p6') },
      div({ class: css('_grid _gc1 _lg:gc2 _gap4') },
        div({ class: css('_flex _col _gap1') },
          h3({ class: css('_heading4') }, 'Notifications'),
          p({ class: css('_bodysm _fgmuted') }, 'Manage notification preferences')
        ),
        div({ class: css('_flex _col _gap4') },
          div({ class: css('_flex _jcsb _aic') },
            Label({}, 'Email Notifications'),
            Switch({})
          ),
          div({ class: css('_flex _jcsb _aic') },
            Label({}, 'Push Notifications'),
            Switch({})
          ),
          div({ class: css('_flex _col _gap2') },
            Label({}, 'Frequency'),
            Select({ options: ['Immediately', 'Daily Digest', 'Weekly'] })
          )
        )
      )
    ),
    div({ class: css('_flex _gap3 _jce') },
      Button({ variant: 'outline', onclick: onCancel }, 'Cancel'),
      Button({ variant: 'primary', type: 'submit' }, 'Save Changes')
    )
  );
}

